-module(solution).
-export([solve/1]).

is_prime(N) when N < 2 -> false;
is_prime(2) -> true;
is_prime(N) when N rem 2 == 0 -> false;
is_prime(N) ->
    Limit = trunc(math:sqrt(N)),
    check_divisors(N, 3, Limit).

check_divisors(N, Divisor, Limit) when Divisor > Limit -> true;
check_divisors(N, Divisor, Limit) when N rem Divisor == 0 -> false;
check_divisors(N, Divisor, Limit) -> check_divisors(N, Divisor + 2, Limit).

solve(nums) ->
    SumA = lists:foldl(
        fun({Index, Value}, Acc) ->
            case is_prime(Index) of
                true -> Acc + Value;
                false -> Acc
            end
        end,
        0,
        lists:zip(lists:seq(0, length(nums) - 1), nums)
    ),
    Total = lists:sum(nums),
    abs(SumA - (Total - SumA)).
